import { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLogin, setIsLogin] = useState(false);
  const [courses, setCourses] = useState([]);

  const handleLogin = async () => {
    await axios.post("http://localhost:5000/login", {
      email,
      password,
    });
    setIsLogin(true);
  };

  useEffect(() => {
    if (isLogin) {
      axios.get("http://localhost:5000/courses").then((res) => {
        setCourses(res.data);
      });
    }
  }, [isLogin]);

  // 🔐 LOGIN UI
  if (!isLogin) {
    return (
      <div style={styles.loginContainer}>
        <div style={styles.loginBox}>
          <h2>🎓 LMS Login</h2>

          <input
            style={styles.input}
            placeholder="Email"
            onChange={(e) => setEmail(e.target.value)}
          />

          <input
            style={styles.input}
            type="password"
            placeholder="Password"
            onChange={(e) => setPassword(e.target.value)}
          />

          <button style={styles.loginBtn} onClick={handleLogin}>
            Login
          </button>
        </div>
      </div>
    );
  }

  // 📊 DASHBOARD UI
  return (
    <div>
      {/* Navbar */}
      <div style={styles.navbar}>
        <h2>LMS Dashboard</h2>
        <button style={styles.logoutBtn} onClick={() => setIsLogin(false)}>
          Logout
        </button>
      </div>

      {/* Courses */}
      <div style={styles.container}>
        {courses.map((course) => (
          <div key={course.id} style={styles.card}>
            <h3>{course.title}</h3>
            <p>{course.description}</p>

            <button style={styles.enrollBtn}>
              Enroll
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

// 🎨 STYLES
const styles = {
  loginContainer: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    height: "100vh",
    background: "#f4f6f8",
  },
  loginBox: {
    background: "white",
    padding: "30px",
    borderRadius: "10px",
    boxShadow: "0 0 10px rgba(0,0,0,0.1)",
    textAlign: "center",
  },
  input: {
    display: "block",
    margin: "10px auto",
    padding: "10px",
    width: "250px",
  },
  loginBtn: {
    padding: "10px 20px",
    background: "#007bff",
    color: "white",
    border: "none",
    cursor: "pointer",
  },
  navbar: {
    display: "flex",
    justifyContent: "space-between",
    padding: "15px",
    background: "#007bff",
    color: "white",
  },
  logoutBtn: {
    background: "white",
    color: "#007bff",
    border: "none",
    padding: "5px 10px",
    cursor: "pointer",
  },
  container: {
    display: "flex",
    flexWrap: "wrap",
    justifyContent: "center",
    marginTop: "20px",
  },
  card: {
    background: "white",
    margin: "15px",
    padding: "20px",
    width: "250px",
    borderRadius: "10px",
    boxShadow: "0 0 10px rgba(0,0,0,0.1)",
    textAlign: "center",
  },
  enrollBtn: {
    marginTop: "10px",
    padding: "8px 15px",
    background: "green",
    color: "white",
    border: "none",
    cursor: "pointer",
  },
};

export default App;
